"""Agentic extraction loop: the LLM drives the browser via tool calls."""
from __future__ import annotations

import json
import logging
from typing import Any

from anthropic import Anthropic
from pydantic import BaseModel

from auto_data.browser import BrowserSession
from auto_data.config import Config
from auto_data.extractor import clean_html
from auto_data.retry import ExtractionError

log = logging.getLogger(__name__)

AGENT_SYSTEM = """You are an autonomous web data-extraction agent driving a real browser.
You navigate, click, fill forms, and read page content to collect data matching the user's goal.

Strategy:
1. Use `read_page` to inspect the current page in compact markdown form.
2. Use `goto`, `click`, `fill` to navigate / interact.
3. When you have gathered enough data, call `finish` with the final JSON object.

Rules:
- Prefer specific CSS selectors. If a click fails, try `read_page` first to find a better one.
- Never invent data. If a field cannot be found, return null / [] in `finish`.
- Stop as soon as the goal is satisfied; do not over-explore.
"""

TOOLS = [
    {
        "name": "goto",
        "description": "Navigate the browser to a URL.",
        "input_schema": {
            "type": "object",
            "properties": {"url": {"type": "string"}},
            "required": ["url"],
        },
    },
    {
        "name": "click",
        "description": "Click an element by CSS selector.",
        "input_schema": {
            "type": "object",
            "properties": {"selector": {"type": "string"}},
            "required": ["selector"],
        },
    },
    {
        "name": "fill",
        "description": "Fill a form field by CSS selector.",
        "input_schema": {
            "type": "object",
            "properties": {
                "selector": {"type": "string"},
                "value": {"type": "string"},
            },
            "required": ["selector", "value"],
        },
    },
    {
        "name": "read_page",
        "description": "Return the current page as compact markdown for inspection.",
        "input_schema": {"type": "object", "properties": {}},
    },
    {
        "name": "finish",
        "description": "Return the final extracted JSON object and end the session.",
        "input_schema": {
            "type": "object",
            "properties": {"data": {"type": "object"}},
            "required": ["data"],
        },
    },
]


class ExtractionAgent:
    """Tool-using agent that navigates a BrowserSession to fulfill an extraction goal."""

    def __init__(self, config: Config, session: BrowserSession):
        self.config = config
        self.session = session
        self.client = Anthropic(api_key=config.anthropic_api_key)

    async def _dispatch(self, name: str, args: dict[str, Any]) -> str:
        try:
            if name == "goto":
                await self.session.goto(args["url"])
                return f"ok: navigated to {args['url']}\nurl now: {self.session.page.url}"
            if name == "click":
                await self.session.click(args["selector"])
                return f"ok: clicked {args['selector']}"
            if name == "fill":
                await self.session.fill(args["selector"], args["value"])
                return f"ok: filled {args['selector']}"
            if name == "read_page":
                html = await self.session.html()
                return clean_html(html, self.config.max_content_chars)
            return f"error: unknown tool {name}"
        except Exception as e:  # surface failures back to the model for self-correction
            return f"error: {type(e).__name__}: {e}"

    async def run(
        self,
        goal: str,
        schema: type[BaseModel] | None = None,
        start_url: str | None = None,
    ) -> BaseModel | dict:
        if start_url:
            await self.session.goto(start_url)

        schema_hint = ""
        if schema is not None:
            schema_hint = f"\n\nThe final `finish` data must match this JSON schema:\n{json.dumps(schema.model_json_schema())}"

        messages: list[dict] = [
            {"role": "user", "content": f"# Goal\n{goal}\n\nCurrent URL: {self.session.page.url}{schema_hint}"}
        ]

        for step in range(self.config.max_agent_steps):
            log.info("agent step %d", step + 1)
            resp = self.client.messages.create(
                model=self.config.model,
                max_tokens=self.config.max_tokens,
                system=[
                    {"type": "text", "text": AGENT_SYSTEM, "cache_control": {"type": "ephemeral"}},
                ],
                tools=TOOLS,
                messages=messages,
            )

            messages.append({"role": "assistant", "content": resp.content})

            if resp.stop_reason != "tool_use":
                # Model stopped without finishing — treat as failure to converge.
                text = "".join(b.text for b in resp.content if getattr(b, "type", None) == "text")
                raise ExtractionError(f"agent ended without finish(): {text[:400]}")

            tool_results = []
            done_payload = None
            for block in resp.content:
                if getattr(block, "type", None) != "tool_use":
                    continue
                if block.name == "finish":
                    done_payload = block.input.get("data", {})
                    tool_results.append(
                        {"type": "tool_result", "tool_use_id": block.id, "content": "ok"}
                    )
                    continue
                result = await self._dispatch(block.name, dict(block.input))
                tool_results.append(
                    {"type": "tool_result", "tool_use_id": block.id, "content": result}
                )

            messages.append({"role": "user", "content": tool_results})

            if done_payload is not None:
                if schema is not None:
                    return schema.model_validate(done_payload)
                return done_payload

        raise ExtractionError(f"agent exceeded max_agent_steps={self.config.max_agent_steps}")

